    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: patients; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.patients (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(255) NOT NULL,
    phone character varying(30) NOT NULL,
    email character varying(255),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    date_of_birth date,
    gender character varying(10),
    blood_type character varying(5),
    no_show_count integer DEFAULT 0 NOT NULL,
    last_minute_cancel_count integer DEFAULT 0 NOT NULL,
    cnam_number character varying(20),
    is_suspended boolean DEFAULT false NOT NULL,
    suspension_reason text,
    suspended_at timestamp with time zone,
    password_hash text,
    email_verified boolean DEFAULT false NOT NULL,
    auth_method character varying(10) DEFAULT 'otp'::character varying NOT NULL,
    cin character varying(20),
    insurance_provider character varying(50),
    insurance_number character varying(30),
    emergency_contact_name character varying(120),
    emergency_contact_phone character varying(30),
    emergency_contact_relation character varying(30),
    height_cm smallint,
    weight_kg numeric(5,2),
    occupation character varying(100),
    marital_status character varying(20),
    preferred_language character varying(5) DEFAULT 'fr'::character varying,
    referring_doctor_id uuid,
    deleted_at timestamp without time zone,
    nationality character varying(40),
    address_street character varying(200),
    address_city character varying(80),
    address_postal_code character varying(10),
    profession_notes text
);


--
-- Name: phone_proxies; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.phone_proxies (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    sos_session_id uuid,
    proxy_number character varying(30) NOT NULL,
    patient_phone character varying(30) NOT NULL,
    doctor_phone character varying(30) NOT NULL,
    twilio_proxy_service_sid character varying(100),
    twilio_session_sid character varying(100),
    expires_at timestamp with time zone NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: platform_settings; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.platform_settings (
    key character varying(100) NOT NULL,
    value text NOT NULL,
    category character varying(50) NOT NULL,
    label character varying(255) NOT NULL,
    description text,
    type character varying(20) DEFAULT 'text'::character varying NOT NULL,
    options jsonb,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: prescriptions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.prescriptions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    appointment_id uuid NOT NULL,
    doctor_id uuid NOT NULL,
    patient_id uuid NOT NULL,
    content text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    verification_token character varying(64)
);


--
-- Name: promo_code_usages; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.promo_code_usages (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    promo_code_id uuid NOT NULL,
    doctor_id uuid NOT NULL,
    applied_to character varying(50),
    discount_amount integer NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: promo_codes; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.promo_codes (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    code character varying(30) NOT NULL,
    type character varying(20) NOT NULL,
    value integer NOT NULL,
    target character varying(20) DEFAULT 'subscription'::character varying NOT NULL,
    max_uses integer,
    current_uses integer DEFAULT 0 NOT NULL,
    valid_from timestamp with time zone DEFAULT now() NOT NULL,
    valid_until timestamp with time zone,
    is_active boolean DEFAULT true NOT NULL,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: push_tokens; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.push_tokens (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    patient_id uuid,
    token text NOT NULL,
    platform character varying(10) NOT NULL,
    device_id character varying(255),
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    actor_type character varying(10) DEFAULT 'patient'::character varying NOT NULL,
    actor_id uuid NOT NULL
);


--
-- Name: referrals; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.referrals (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    referrer_id uuid NOT NULL,
    referred_id uuid NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    validated_at timestamp with time zone
);


--
-- Name: reviews; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.reviews (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    doctor_id uuid NOT NULL,
    patient_id uuid NOT NULL,
    appointment_id uuid,
    rating integer NOT NULL,
    comment text,
    verified boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    sos_session_id uuid,
    rejection_reason text,
    moderated_by uuid,
    moderated_at timestamp with time zone
);


--
-- Name: secretaries; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.secretaries (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    doctor_id uuid NOT NULL,
    name character varying(255) NOT NULL,
    email character varying(255) NOT NULL,
    password_hash text NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    clinic_id uuid,
    permissions jsonb DEFAULT '{"agenda": true, "motifs": true, "wallet": false, "cabinets": false, "factures": false, "patients": true, "messagerie": false, "rendezVous": true, "teleconsult": false}'::jsonb NOT NULL,
    phone character varying(30),
    date_of_birth date,
    years_of_experience integer,
    monthly_salary integer,
    hire_date date,
    last_active_at timestamp without time zone,
    photo_url text,
    bio text,
    monthly_day_off_allowance numeric(4,1) DEFAULT 2.0
);


--
-- Name: secretary_notifications; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.secretary_notifications (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    secretary_id uuid NOT NULL,
    type character varying(30) NOT NULL,
    title character varying(255) NOT NULL,
    body text,
    payload jsonb DEFAULT '{}'::jsonb NOT NULL,
    read_at timestamp without time zone,
    seen_at timestamp without time zone,
    created_at timestamp without time zone DEFAULT now()
);


--
-- Name: secretary_schedules; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.secretary_schedules (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    secretary_id uuid NOT NULL,
    day_of_week integer NOT NULL,
    start_time time without time zone NOT NULL,
    end_time time without time zone NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    created_at timestamp without time zone DEFAULT now(),
    CONSTRAINT secretary_schedules_day_of_week_check CHECK (((day_of_week >= 0) AND (day_of_week <= 6))),
    CONSTRAINT secretary_schedules_hours CHECK ((start_time < end_time))
);


--
-- Name: secretary_time_off; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.secretary_time_off (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    secretary_id uuid NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    reason text,
    status character varying(10) DEFAULT 'pending'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT now(),
    decided_at timestamp without time zone,
    CONSTRAINT secretary_time_off_range CHECK ((end_date >= start_date))
);


--
-- Name: sms_logs; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sms_logs (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    recipient character varying(30) NOT NULL,
    message text NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    provider character varying(50),
    cost integer,
    appointment_id uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: sms_usage; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sms_usage (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    doctor_id uuid NOT NULL,
    month character varying(7) NOT NULL,
    count integer DEFAULT 0 NOT NULL
);


--
-- Name: sos_declines; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sos_declines (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    session_id uuid NOT NULL,
    doctor_id uuid NOT NULL,
    reason character varying(30),
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: sos_sessions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.sos_sessions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    patient_id uuid NOT NULL,
    patient_lat double precision NOT NULL,
    patient_lng double precision NOT NULL,
    patient_location public.geography(Point,4326) NOT NULL,
    symptom_category character varying(50),
    description text,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    doctor_id uuid,
    fee integer,
    commission integer,
    requested_at timestamp with time zone DEFAULT now() NOT NULL,
    accepted_at timestamp with time zone,
    completed_at timestamp with time zone,
    expires_at timestamp with time zone NOT NULL,
    cancelled_at timestamp with time zone,
    cancel_reason text,
    cancelled_by character varying(10),
    distance_m integer,
    admin_notes text,
    resolution character varying(20)
);


--
-- Name: staff_conversations; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.staff_conversations (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    doctor_id uuid NOT NULL,
    member_a_type character varying(10) NOT NULL,
    member_a_id uuid NOT NULL,
    member_b_type character varying(10) NOT NULL,
    member_b_id uuid NOT NULL,
    last_message_at timestamp without time zone,
    created_at timestamp without time zone DEFAULT now(),
    CONSTRAINT staff_conv_members_distinct CHECK ((((member_a_type)::text <> (member_b_type)::text) OR (member_a_id <> member_b_id)))
);


--
-- Name: staff_messages; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.staff_messages (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    conversation_id uuid NOT NULL,
    sender_type character varying(10) NOT NULL,
    sender_id uuid NOT NULL,
    body text NOT NULL,
    read_at timestamp without time zone,
    created_at timestamp without time zone DEFAULT now()
);


--
-- Name: subscription_plans; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.subscription_plans (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    code character varying(20) NOT NULL,
    label character varying(100) NOT NULL,
    price_millimes integer NOT NULL,
    billing_cycle character varying(20) DEFAULT 'monthly'::character varying NOT NULL,
    features jsonb DEFAULT '[]'::jsonb NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    display_order integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: subscriptions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.subscriptions (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    doctor_id uuid NOT NULL,
    plan character varying(20) NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    price_millimes integer NOT NULL,
    billing_cycle character varying(20) DEFAULT 'monthly'::character varying NOT NULL,
    payment_provider character varying(20),
    external_ref character varying(255),
    starts_at timestamp with time zone,
    ends_at timestamp with time zone,
    cancelled_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: teleconsultations; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.teleconsultations (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    appointment_id uuid NOT NULL,
    room_name character varying(100) NOT NULL,
